# Unit Tests for `parse_csv_line`

```python
import pytest
from mymodule import parse_csv_line  # adjust import as needed


class TestParseCsvLineHappyPath:
    """Tests for typical, expected inputs."""

    def test_simple_comma_separated_values(self):
        assert parse_csv_line("a,b,c") == ["a", "b", "c"]

    def test_single_value_no_commas(self):
        assert parse_csv_line("hello") == ["hello"]

    def test_numeric_values_as_strings(self):
        assert parse_csv_line("1,2,3") == ["1", "2", "3"]

    def test_quoted_values(self):
        assert parse_csv_line('"a","b","c"') == ["a", "b", "c"]

    def test_quoted_value_containing_comma(self):
        assert parse_csv_line('a,"b,c",d') == ["a", "b,c", "d"]

    def test_mixed_quoted_and_unquoted(self):
        assert parse_csv_line('foo,"bar,baz",qux') == ["foo", "bar,baz", "qux"]

    def test_multiple_quoted_commas(self):
        assert parse_csv_line('"a,b","c,d","e,f"') == ["a,b", "c,d", "e,f"]

    def test_values_with_spaces(self):
        assert parse_csv_line("hello world, foo bar, baz") == [
            "hello world",
            " foo bar",
            " baz",
        ]


class TestParseCsvLineEdgeCases:
    """Tests for edge cases and unusual inputs."""

    def test_empty_string(self):
        assert parse_csv_line("") == [""]

    def test_only_a_comma(self):
        assert parse_csv_line(",") == ["", ""]

    def test_multiple_consecutive_commas(self):
        assert parse_csv_line(",,,") == ["", "", "", ""]

    def test_trailing_comma(self):
        assert parse_csv_line("a,b,") == ["a", "b", ""]

    def test_leading_comma(self):
        assert parse_csv_line(",a,b") == ["", "a", "b"]

    def test_empty_quoted_string(self):
        assert parse_csv_line('""') == [""]

    def test_empty_quoted_strings_among_values(self):
        assert parse_csv_line('a,"",b') == ["a", "", "b"]

    def test_only_quotes(self):
        # Quotes are stripped; toggling produces empty content
        assert parse_csv_line('""""') == [""]

    def test_single_quote_character(self):
        # Single quote opens quoting but never closes; result is one field with no quote chars
        assert parse_csv_line('"a,b') == ["a,b"]

    def test_whitespace_only_field(self):
        assert parse_csv_line("   ") == ["   "]

    def test_whitespace_around_commas_preserved(self):
        assert parse_csv_line(" a , b , c ") == [" a ", " b ", " c "]

    def test_special_characters(self):
        assert parse_csv_line("a!@#,b$%^,c&*()") == ["a!@#", "b$%^", "c&*()"]

    def test_unicode_characters(self):
        assert parse_csv_line("café,naïve,日本") == ["café", "naïve", "日本"]

    def test_newline_inside_field(self):
        assert parse_csv_line("a\nb,c") == ["a\nb", "c"]

    def test_tab_inside_field(self):
        assert parse_csv_line("a\tb,c") == ["a\tb", "c"]

    def test_quotes_in_middle_of_field(self):
        # Quotes around a substring still toggle in_quotes state
        assert parse_csv_line('a"b,c"d') == ['ab,cd']

    def test_long_input(self):
        line = ",".join(str(i) for i in range(1000))
        result = parse_csv_line(line)
        assert len(result) == 1000
        assert result[0] == "0"
        assert result[-1] == "999"

    def test_returns_list_type(self):
        assert isinstance(parse_csv_line("a,b"), list)

    def test_quoted_field_with_only_commas(self):
        assert parse_csv_line('",,,"') == [",,,"]


class TestParseCsvLineErrorCases:
    """Tests for invalid input types that should raise errors."""

    def test_none_input_raises(self):
        with pytest.raises(TypeError):
            parse_csv_line(None)

    def test_integer_input_raises(self):
        with pytest.raises(TypeError):
            parse_csv_line(12345)

    def test_list_input_raises(self):
        with pytest.raises(TypeError):
            parse_csv_line(["a", "b"])

    def test_dict_input_raises(self):
        with pytest.raises(TypeError):
            parse_csv_line({"a": 1})

    def test_float_input_raises(self):
        with pytest.raises(TypeError):
            parse_csv_line(3.14)


@pytest.mark.parametrize(
    "line,expected",
    [
        ("a,b,c", ["a", "b", "c"]),
        ("", [""]),
        (",", ["", ""]),
        ('"x,y",z', ["x,y", "z"]),
        ("single", ["single"]),
        ('"hello"', ["hello"]),
        ("a,,b", ["a", "", "b"]),
    ],
)
def test_parse_csv_line_parametrized(line, expected):
    assert parse_csv_line(line) == expected
